module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output reg o_en
);

    reg [63:0] reg_a, reg_b;
    reg [64:0] reg_sum;
    reg [1:0] pipeline_stage;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_a <= 64'b0;
            reg_b <= 64'b0;
            reg_sum <= 65'b0;
            pipeline_stage <= 2'b00;
            o_en <= 1'b0;
        end else begin
            case (pipeline_stage)
                2'b00: begin
                    if (i_en) begin
                        reg_a <= adda;
                        reg_b <= addb;
                        pipeline_stage <= 2'b01;
                    end
                end
                2'b01: begin
                    reg_sum <= reg_a + reg_b;
                    pipeline_stage <= 2'b10;
                end
                2'b10: begin
                    reg_sum <= reg_sum;
                    pipeline_stage <= 2'b11;
                end
                2'b11: begin
                    reg_sum <= reg_sum;
                    pipeline_stage <= 2'b00;
                    o_en <= 1'b1;
                end
            endcase
        end
    end

    assign result = reg_sum;

endmodule

